INSERT INTO supplemental_essays (id, college_id, prompt, word_limit) VALUES (gen_random_uuid(), (SELECT id FROM colleges WHERE full_name = 'Massachusetts Institute of Technology'), 'We know you lead a busy life, full of activities, many of which are required of you. Tell us about something you do simply for the pleasure of it.', 200);
INSERT INTO supplemental_essays (id, college_id, prompt, word_limit) VALUES (gen_random_uuid(), (SELECT id FROM colleges WHERE full_name = 'Massachusetts Institute of Technology'), 'Describe the world you come from (for example, your family, school, community, city, or town). How has that world shaped your dreams and aspirations?', 200);
INSERT INTO supplemental_essays (id, college_id, prompt, word_limit) VALUES (gen_random_uuid(), (SELECT id FROM colleges WHERE full_name = 'Massachusetts Institute of Technology'), 'MIT brings people with diverse backgrounds and experiences together to better the lives of others. Our students work to improve their communities in different ways, from tackling the world’s biggest challenges to being a good friend. Describe one way you have collaborated with people who are different from you to contribute to your community.', 200);
INSERT INTO supplemental_essays (id, college_id, prompt, word_limit) VALUES (gen_random_uuid(), (SELECT id FROM colleges WHERE full_name = 'Massachusetts Institute of Technology'), 'Tell us about a significant challenge you’ve faced (that you feel comfortable sharing) or something that didn’t go according to plan. How did you manage the situation?', 200);
